const { MongoClient } = require('mongodb');
const { v4: uuidv4 } = require('uuid');

const uri = 'mongodb://localhost:27017';
const client = new MongoClient(uri, { useNewUrlParser: true, useUnifiedTopology: true });

async function applyCoupon(userId, couponCode) {
  try {
    await client.connect();
    const database = client.db('shop');
    const coupons = database.collection('coupons');
    const users = database.collection('users');

    const session = client.startSession();
    session.startTransaction();

    try {
      const coupon = await coupons.findOne({ code: couponCode }, { session });
      if (!coupon) throw new Error('Coupon not found');
      if (coupon.expiryDate < new Date()) throw new Error('Coupon expired');
      if (coupon.used) throw new Error('Coupon already used');

      const user = await users.findOne({ _id: userId }, { session });
      if (!user) throw new Error('User not found');

      const discount = coupon.discount;
      const newTotal = user.cartTotal - (user.cartTotal * discount / 100);

      await coupons.updateOne({ code: couponCode }, { $set: { used: true } }, { session });
      await users.updateOne({ _id: userId }, { $set: { cartTotal: newTotal } }, { session });

      await session.commitTransaction();
      console.log('Coupon applied successfully');
    } catch (error) {
      await session.abortTransaction();
      console.error('Transaction aborted due to error:', error);
    } finally {
      session.endSession();
    }
  } finally {
    await client.close();
  }
}

